const nodes = msg.payload;

const cluster = new redis.Cluster(nodes);

cluster.on('ready', async () => {
    const allNodes = cluster.nodes('all');

    await Promise.all(
        allNodes.map(node =>
            node.config('SET', 'notify-keyspace-events', 'KEx')
        )
    );

    node.warn('Keyspace events configured on all nodes');
    await cluster.quit();
    node.send(msg);
});

cluster.on('error', (err) => {
    node.error('Cluster error: ' + err.message);
});

